INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-d0d1b9a2-moex-00014', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X2年度淨利為$700,000，稅率為20%。全年有普通股200,000股流通在外。若該公司於 X2年初有10%可轉換公司債，面額為$100，流通在外20,000張，每張可換成普通股2股，發行 價格中的負債組成要素相當於面額。此外，該公司X1年初發行賣權6,000個，每個得依$20之 價格賣回1股面額為$10的普通股給公司，普通股全年平均市價為$12。下列何者為用於計算X2年 度稀釋每股盈餘的股數？', '["200,000股", "204,000股", "220,000股", "244,000股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00015', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$2,000,000購入一筆土地，X1年底該土地之公允價值為$3,000,000，X2年9月 進行重估價後，以當時之公允價值$3,800,000售出。若甲公司採重估價模式作後續衡量，且處分 時將累計之重估增值轉入保留盈餘，則X2年底股東權益因為出售土地而增加的淨額為何？', '["$800,000", "$1,000,000", "$1,800,000", "$2,100,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00016', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司因資金短缺，於X1年5月1日將客戶之應收帳款$1,000,000，以有限追索權方式出售給 乙銀行，甲公司保證所移轉之應收帳款至少可收現$700,000。乙銀行負責向客戶收款且不得轉售 該應收帳款，並向甲公司收取應收帳款總額 4%之手續費。甲公司獲得現金$960,000，該保證負 債之公允價值為$3,300。試問對於甲公司而言，於X1年5月1日之相關分錄，下列何者正確？', '["借記：出售金融資產損失$43,300", "借記：手續費用$40,000", "貸記：保證負債$700,000", "貸記：金融資產移轉負債$303,300"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00017', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$3,000,000買入高污染設備，耐用年限3年，預計3年後無殘值，採直線法 提列折舊。但法令規定3年後須以環保方式處置該設備。若該公司折現率為10%，且估計3年後 須花$100,000處理費，則X1年甲公司應報導與此高污染設備相關的全部費用金額為何？', '["$1,000,000", "$1,025,044", "$1,032,557", "$1,036,667"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00018', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司銷售電器用品並提供2年期的保固服務，保固合約不單獨銷售。該公司於X5年以現金銷 售800台電器用品（每台單價$25,000），並估計每台保固成本為$1,000。實際於X5年支付零件 費$80,000與人工費$35,000。甲公司於銷售時預估並認列保固負債及保固費用。但會計人員誤以 現金基礎記帳，僅在實際支付時認列費用。試問此錯誤將如何影響甲公司X5年之財報比率？', '["流動比率高估、利潤率高估", "流動比率低估、利潤率高估", "流動比率高估、利潤率低估", "流動比率低估、利潤率低估"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00019', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年成立時以每股$25，發行面額$10的普通股30,000股。該公司於X2年5月13日首 次以每股$28購回庫藏股5,000股，並於X2年6月24日及7月1日分別以每股$32及$24的價 格各出售2,000股，X2年9月3日又註銷剩餘1,000股。請問X2年4項庫藏股交易如何影響股 東權益的總金額？', '["減少$3,000", "減少$8,000", "減少$28,000", "減少$143,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00020', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '有關債券投資之敘述，下列何者正確？', '["若債券是折價投資，隨著時間經過，各期攤銷之折價數額會越來越少", "若債券是溢價投資，隨著時間經過，各期認列之利息收入會越來越高", "不論債券是折價或溢價投資，隨著時間經過，各期攤銷之折溢價數額均會越來越高", "不論債券是折價或溢價投資，隨著時間經過，各期認列之利息收入均會越來越低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00021', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X8年度之稅後淨利為$500,000，當年度並有下列事項：', '["應付公司債溢價攤銷$10,000", "遞延所得稅資產減少$6,000", "透過其他綜合損益按公允價值衡量投資（流動資產），投資金額增加$15,000", "待出售非流動資產之處分利益$8,000 請問甲公司X8年度營業活動之現金流量為何？"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00022', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初對其40位經理人員施行一項認股權計畫，若於X3年底尚在職者，則每人得以 $100認購公司股票，每人之認購股數依公司X3年底之市占率成長幅度而定，每成長5%之認購 股數為1,000，若成長10%認購股數則為2,000，以此類推。相關資料如下： 估計每個認股權公 當年度實際離職 估計X3年底前尚會 估計 X3 年底之市 日期 允價值 人數 離職人數 占率成長幅度 X1年初 $20 10% X1年底 $25 5 5 5% X2年底 $22 8 4 10% 有關甲公司此項認股權計畫，下列敘述何者正確？', '["X1年度應認列之酬勞成本為$250,000", "X2年度應認列之酬勞成本為$413,333", "X1年底相關之資本公積為$400,000", "X2年底相關之資本公積為$674,666"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00023', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'essay', '甲公務機關 X6年度決算報告顯示下列資料：
